  from dataclasses import dataclass
  import re

  def _strip_quotes(text: str) -> str:
      """Remove surrounding quotes from a string if present."""
      return text.strip('\'"')

  def _ordinal(n_str: str) -> str:
      """Convert a numeric string to an ordinal representation (e.g., '1' -> '1st')."""
      try:
          n = int(n_str)
      except ValueError:
          return n_str
      suffix = 'th'
      if 10 <= n % 100 <= 20:
          suffix = 'th'
      else:
          suffix = {1: 'st', 2: 'nd', 3: 'rd'}.get(n % 10, 'th')
      return f"{n}{suffix}"

